// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





export default function Component(props: Props) {
  // Helper function to get weather emoji based on condition
  const getWeatherEmoji = (condition: string): string => {
    const conditionLower = condition.toLowerCase();
    if (conditionLower.includes('sunny') || conditionLower.includes('clear')) return '☀️';
    if (conditionLower.includes('cloudy') || conditionLower.includes('overcast')) return '☁️';
    if (conditionLower.includes('rainy') || conditionLower.includes('rain')) return '🌧️';
    if (conditionLower.includes('snow') || conditionLower.includes('snowy')) return '❄️';
    if (conditionLower.includes('storm') || conditionLower.includes('thunder')) return '⛈️';
    if (conditionLower.includes('wind') || conditionLower.includes('windy')) return '💨';
    if (conditionLower.includes('fog') || conditionLower.includes('mist')) return '🌫️';
    return '🌤️'; // Default to partly cloudy
  };

  // Get weather emoji for current condition
  const weatherEmoji = getWeatherEmoji(props.condition);

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Main weather card */}
        <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            {/* City and basic info header */}
            <Stack direction="horizontal" justify="between" align="center">
              <Heading level={2} color="var(--ggui-color-onSurface)">{props.city}</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">{props.unit}°</Text>
            </Stack>

            {/* Temperature and condition display */}
            <Stack align="center" gap="var(--ggui-spacing-2)">
              <Row align="center" gap="var(--ggui-spacing-3)">
                <Icon name={weatherEmoji} size={80} />
                <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface)" align="left" style={{ lineHeight: '1' }}>
                  {Math.round(props.temperature)}°
                </Text>
              </Row>
              <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant)">{props.condition}</Text>
            </Stack>

            {/* Humidity and Wind Speed */}
            <Divider margin="var(--ggui-spacing-4)" />
            <Row gap="var(--ggui-spacing-4)" justify="around" align="stretch">
              <Stack align="center" gap="var(--ggui-spacing-2)" style={{ flex: 1 }}>
                <Icon name="droplets" size={24} color="var(--ggui-color-primary-600)" />
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
                <Text size="lg" weight="semibold" color="var(--ggui-color-onSurface)">{props.humidity}%</Text>
              </Stack>
              <Divider orientation="vertical" margin="var(--ggui-spacing-2)" />
              <Stack align="center" gap="var(--ggui-spacing-2)" style={{ flex: 1 }}>
                <Icon name="wind" size={24} color="var(--ggui-color-primary-600)" />
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Wind Speed</Text>
                <Text size="lg" weight="semibold" color="var(--ggui-color-onSurface)">{props.windSpeed} km/h</Text>
              </Stack>
            </Row>
          </Stack>
        </Card>

        {/* 5-Day Forecast */}
        <Stack gap="var(--ggui-spacing-3)">
          <Heading level={4} color="var(--ggui-color-onSurface)">5-Day Forecast</Heading>
          <Row gap="var(--ggui-spacing-3)" wrap style={{ justifyContent: 'space-between' }}>
            {props.forecast && props.forecast.length > 0 ? (
              props.forecast.map((day, index) => (
                <Card
                  key={index}
                  shadow="sm"
                  padding="var(--ggui-spacing-4)"
                  radius="md"
                  style={{
                    flex: '1 1 calc(20% - var(--ggui-spacing-2))',
                    minWidth: '100px',
                    textAlign: 'center',
                  }}
                >
                  <Stack align="center" gap="var(--ggui-spacing-2)">
                    <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface)">
                      {day.day || `Day ${index + 1}`}
                    </Text>
                    <Icon name={day.icon || '🌤️'} size={32} />
                    <Stack align="center" gap="var(--ggui-spacing-1)">
                      <Text size="sm" weight="semibold" color="var(--ggui-color-onSurface)">
                        {day.high !== undefined ? `${Math.round(day.high)}°` : 'N/A'}
                      </Text>
                      <Text size="sm" color="var(--ggui-color-onSurfaceVariant)">
                        {day.low !== undefined ? `${Math.round(day.low)}°` : 'N/A'}
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              ))
            ) : (
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                No forecast data available
              </Text>
            )}
          </Row>
        </Stack>
      </Stack>
    </Container>
  );
}

