import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





export default function Component(props: Props) {
  // Wire hooks
  const submit = useAction<ActionSubmitPayload>('submit');

  // State
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: 0,
    features: [] as string[],
    comments: '',
  });
  const [errors, setErrors] = useState({
    name: '',
    email: '',
  });

  // Validation helpers
  const validateEmail = (email: string): boolean => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  };

  const validateStep1 = (): boolean => {
    const newErrors = { name: '', email: '' };
    let isValid = true;

    if (!formData.name.trim()) {
      newErrors.name = 'Name is required';
      isValid = false;
    }

    if (!formData.email.trim()) {
      newErrors.email = 'Email is required';
      isValid = false;
    } else if (!validateEmail(formData.email)) {
      newErrors.email = 'Please enter a valid email address';
      isValid = false;
    }

    setErrors(newErrors);
    return isValid;
  };

  // Handlers
  const handleNameChange = (value: string) => {
    setFormData(prev => ({ ...prev, name: value }));
    if (errors.name) setErrors(prev => ({ ...prev, name: '' }));
  };

  const handleEmailChange = (value: string) => {
    setFormData(prev => ({ ...prev, email: value }));
    if (errors.email) setErrors(prev => ({ ...prev, email: '' }));
  };

  const handleSatisfactionChange = (value: string) => {
    setFormData(prev => ({ ...prev, satisfaction: parseInt(value, 10) }));
  };

  const handleFeatureToggle = (feature: string) => {
    setFormData(prev => ({
      ...prev,
      features: prev.features.includes(feature)
        ? prev.features.filter(f => f !== feature)
        : [...prev.features, feature],
    }));
  };

  const handleCommentsChange = (value: string) => {
    if (value.length <= 500) {
      setFormData(prev => ({ ...prev, comments: value }));
    }
  };

  const handleNext = () => {
    if (currentStep === 1 && !validateStep1()) {
      return;
    }
    if (currentStep < 5) {
      setCurrentStep(currentStep + 1);
    }
  };

  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  const handleSubmit = () => {
    submit({
      name: formData.name,
      email: formData.email,
      satisfaction: formData.satisfaction,
      features: formData.features,
      comments: formData.comments,
    });
  };

  // Computed values
  const isStep1Valid = formData.name.trim() !== '' && validateEmail(formData.email);
  const isStep2Valid = formData.satisfaction > 0;
  const satisfactionOptions = props.satisfactionLabels.map((label, index) => ({
    value: String(index + 1),
    label: `${index + 1} - ${label}`,
  }));
  const featureOptions = props.featureOptions.map(feature => ({
    value: feature,
    label: feature,
  }));

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)" align="stretch">
        {/* Progress Bar */}
        <Card shadow="none" border={false} padding="var(--ggui-spacing-4)">
          <Stack gap="var(--ggui-spacing-3)" align="stretch">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" align="center" role="status" aria-live="polite">
              Step {currentStep} of 4
            </Text>
            <Progress value={currentStep} max={4} variant="default" size="md" />
          </Stack>
        </Card>

        {/* Step 1: Name & Email */}
        {currentStep === 1 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)">
            <Stack gap="var(--ggui-spacing-4)" align="stretch">
              <Heading level={3}>Personal Information</Heading>
              <Input
                label="Name"
                value={formData.name}
                onChange={handleNameChange}
                placeholder="Your full name"
                required
                error={errors.name}
              />
              <Input
                label="Email"
                type="email"
                value={formData.email}
                onChange={handleEmailChange}
                placeholder="your@email.com"
                required
                error={errors.email}
              />
            </Stack>
          </Card>
        )}

        {/* Step 2: Satisfaction Rating */}
        {currentStep === 2 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)">
            <Stack gap="var(--ggui-spacing-4)" align="stretch">
              <Heading level={3}>Satisfaction Rating</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                How satisfied are you with our service?
              </Text>
              <RadioGroup
                label="Rating"
                value={String(formData.satisfaction)}
                onChange={handleSatisfactionChange}
                options={satisfactionOptions}
                direction="vertical"
                aria-required="true"
              />
            </Stack>
          </Card>
        )}

        {/* Step 3: Feature Interests */}
        {currentStep === 3 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)">
            <Stack gap="var(--ggui-spacing-4)" align="stretch">
              <Heading level={3}>Feature Interests</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                Which features interest you? (Select all that apply)
              </Text>
              <Stack gap="var(--ggui-spacing-2)" align="stretch">
                {featureOptions.map(feature => (
                  <Checkbox
                    key={feature.value}
                    label={feature.label}
                    checked={formData.features.includes(feature.value)}
                    onChange={() => handleFeatureToggle(feature.value)}
                    aria-required="true"
                  />
                ))}
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 4: Comments */}
        {currentStep === 4 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)">
            <Stack gap="var(--ggui-spacing-4)" align="stretch">
              <Heading level={3}>Additional Comments</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                Please share any additional feedback (optional)
              </Text>
              <TextArea
                label="Comments"
                value={formData.comments}
                onChange={handleCommentsChange}
                placeholder="Your comments here..."
                rows={6}
                maxLength={500}
                showCount
              />
            </Stack>
          </Card>
        )}

        {/* Step 5: Review */}
        {currentStep === 5 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)" role="region" aria-label="Review your survey answers">
            <Stack gap="var(--ggui-spacing-4)" align="stretch">
              <Heading level={3}>Review Your Answers</Heading>
              <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />
              <Stack gap="var(--ggui-spacing-3)" align="stretch">
                <Stack gap="var(--ggui-spacing-1)" align="stretch">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Name</Text>
                  <Text variant="body">{formData.name}</Text>
                </Stack>
                <Stack gap="var(--ggui-spacing-1)" align="stretch">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Email</Text>
                  <Text variant="body">{formData.email}</Text>
                </Stack>
                <Stack gap="var(--ggui-spacing-1)" align="stretch">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Satisfaction Rating</Text>
                  <Text variant="body">
                    {formData.satisfaction > 0 ? `${formData.satisfaction} - ${props.satisfactionLabels[formData.satisfaction - 1]}` : 'Not selected'}
                  </Text>
                </Stack>
                <Stack gap="var(--ggui-spacing-1)" align="stretch">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Interested Features</Text>
                  {formData.features.length > 0 ? (
                    <Row gap="var(--ggui-spacing-2)" wrap>
                      {formData.features.map(feature => (
                        <Badge key={feature} variant="primary">
                          {feature}
                        </Badge>
                      ))}
                    </Row>
                  ) : (
                    <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                      No features selected
                    </Text>
                  )}
                </Stack>
                <Stack gap="var(--ggui-spacing-1)" align="stretch">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Comments</Text>
                  <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                    {formData.comments || '(No comments provided)'}
                  </Text>
                </Stack>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Navigation Buttons */}
        <Box padding="var(--ggui-spacing-4)" role="navigation" aria-label="Survey navigation">
          <Stack gap="var(--ggui-spacing-3)" justify="between" align="center">
            <Button
              variant="ghost"
              onClick={handleBack}
              disabled={currentStep === 1}
            >
              Back
            </Button>
            {currentStep === 5 ? (
              <Button
                variant="primary"
                onClick={handleSubmit}
              >
                Submit
              </Button>
            ) : (
              <Button
                variant="primary"
                onClick={handleNext}
                disabled={
                  (currentStep === 1 && !isStep1Valid) ||
                  (currentStep === 2 && !isStep2Valid)
                }
              >
                Next
              </Button>
            )}
          </Stack>
        </Box>
      </Stack>
    </Container>
  );
}

