interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}





export default function Component(props: Props) {
  // State for search and selection
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<typeof props.elements[0] | null>(null);

  // Filter elements by search query (case-insensitive)
  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return props.elements;
    const query = searchQuery.toLowerCase();
    return props.elements.filter((el) => {
      const name = el.name?.toLowerCase() || '';
      const symbol = el.symbol?.toLowerCase() || '';
      return name.includes(query) || symbol.includes(query);
    });
  }, [searchQuery, props.elements]);

  // Get unique categories for legend
  const categories = useMemo(() => {
    const uniqueCategories = new Set(props.elements.map((el) => el.category).filter(Boolean));
    return Array.from(uniqueCategories).sort();
  }, [props.elements]);

  // Category to color mapping using design tokens
  const getCategoryColor = (category?: string): string => {
    const colorMap: Record<string, string> = {
      'alkali metal': 'var(--ggui-color-primary-100)',
      'alkaline earth metal': 'var(--ggui-color-primary-100)',
      'transition metal': 'var(--ggui-color-info-100)',
      'lanthanide': 'var(--ggui-color-warning-100)',
      'actinide': 'var(--ggui-color-error-100)',
      'other metal': 'var(--ggui-color-success-100)',
      'semimetal': 'var(--ggui-color-primary-200)',
      'nonmetal': 'var(--ggui-color-info-200)',
      'halogen': 'var(--ggui-color-warning-200)',
      'noble gas': 'var(--ggui-color-success-200)',
    };
    return colorMap[category?.toLowerCase() || ''] || 'var(--ggui-color-surface)';
  };

  const getCategoryBorder = (category?: string): string => {
    const borderMap: Record<string, string> = {
      'alkali metal': 'var(--ggui-color-primary-300)',
      'alkaline earth metal': 'var(--ggui-color-primary-300)',
      'transition metal': 'var(--ggui-color-info-300)',
      'lanthanide': 'var(--ggui-color-warning-300)',
      'actinide': 'var(--ggui-color-error-300)',
      'other metal': 'var(--ggui-color-success-300)',
      'semimetal': 'var(--ggui-color-primary-300)',
      'nonmetal': 'var(--ggui-color-info-300)',
      'halogen': 'var(--ggui-color-warning-300)',
      'noble gas': 'var(--ggui-color-success-300)',
    };
    return borderMap[category?.toLowerCase() || ''] || 'var(--ggui-color-outline)';
  };

  return (
    <Container maxWidth="3xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header */}
        <Stack gap="var(--ggui-spacing-2)" align="center">
          <Heading level={1} color="var(--ggui-color-primary-600)">Periodic Table of Elements</Heading>
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
            Interactive periodic table. Click an element to view details.
          </Text>
        </Stack>

        {/* Search Input */}
        <Input
          label="Search by name or symbol"
          placeholder="e.g., Gold or Au"
          value={searchQuery}
          onChange={setSearchQuery}
          type="search"
        />

        {/* Legend */}
        <Card padding="var(--ggui-spacing-4)" shadow="sm">
          <Stack gap="var(--ggui-spacing-3)">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Category Legend</Text>
            <Row gap="var(--ggui-spacing-4)" wrap>
              {categories.map((category) => (
                <Row key={category} gap="var(--ggui-spacing-2)" align="center">
                  <Box
                    style={{
                      width: '16px',
                      height: '16px',
                      borderRadius: 'var(--ggui-shape-radius-sm)',
                      backgroundColor: getCategoryColor(category),
                      border: `2px solid ${getCategoryBorder(category)}`,
                    }}
                  />
                  <Text variant="bodySmall" color="var(--ggui-color-onSurface)">{category}</Text>
                </Row>
              ))}
            </Row>
          </Stack>
        </Card>

        {/* Periodic Table Grid */}
        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-2)',
            padding: 'var(--ggui-spacing-4)',
            backgroundColor: 'var(--ggui-color-surface)',
            borderRadius: 'var(--ggui-shape-radius-lg)',
            border: '1px solid var(--ggui-color-outline)',
          }}
        >
          {filteredElements.map((element) => {
            const gridRow = element.row || 1;
            const gridCol = element.col || 1;
            const isSelected = selectedElement?.atomicNumber === element.atomicNumber;

            return (
              <Card
                key={element.atomicNumber}
                as={Clickable}
                onClick={() => setSelectedElement(element)}
                padding="var(--ggui-spacing-2)"
                shadow={isSelected ? 'md' : 'sm'}
                style={{
                  gridRow: gridRow.toString(),
                  gridColumn: gridCol.toString(),
                  backgroundColor: getCategoryColor(element.category),
                  border: `2px solid ${getCategoryBorder(element.category)}`,
                  cursor: 'pointer',
                  transition: 'all 0.2s ease-in-out',
                  opacity: searchQuery.trim() && !filteredElements.includes(element) ? 0.3 : 1,
                }}
              >
                <Stack gap="0" align="center" justify="center">
                  <Text
                    variant="caption"
                    color="var(--ggui-color-onSurfaceVariant)"
                    align="left"
                    size="xs"
                    style={{ alignSelf: 'flex-start', marginBottom: 'var(--ggui-spacing-1)' }}
                  >
                    {element.atomicNumber}
                  </Text>
                  <Text
                    variant="label"
                    size="lg"
                    weight="bold"
                    color="var(--ggui-color-onSurface)"
                    align="center"
                  >
                    {element.symbol}
                  </Text>
                  <Text
                    variant="caption"
                    size="xs"
                    color="var(--ggui-color-onSurfaceVariant)"
                    align="center"
                  >
                    {element.name?.substring(0, 8)}
                  </Text>
                </Stack>
              </Card>
            );
          })}
        </Box>

        {/* Detail Panel */}
        {selectedElement && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Row justify="between" align="center">
                <Stack gap="var(--ggui-spacing-1)">
                  <Heading level={2} color="var(--ggui-color-primary-600)">
                    {selectedElement.name}
                  </Heading>
                  <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant)">
                    {selectedElement.symbol}
                  </Text>
                </Stack>
                <Badge variant="primary" size="lg">
                  #{selectedElement.atomicNumber}
                </Badge>
              </Row>

              <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />

              <Row gap="var(--ggui-spacing-6)" wrap>
                <Stack gap="var(--ggui-spacing-1)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" size="sm">
                    Atomic Weight
                  </Text>
                  <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-onSurface)">
                    {selectedElement.atomicWeight?.toFixed(2) || 'N/A'}
                  </Text>
                </Stack>

                <Stack gap="var(--ggui-spacing-1)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" size="sm">
                    Category
                  </Text>
                  <Badge
                    variant="primary"
                    size="md"
                    style={{
                      backgroundColor: getCategoryColor(selectedElement.category),
                      color: 'var(--ggui-color-onSurface)',
                    }}
                  >
                    {selectedElement.category || 'Unknown'}
                  </Badge>
                </Stack>

                <Stack gap="var(--ggui-spacing-1)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" size="sm">
                    Position
                  </Text>
                  <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-onSurface)">
                    Row {selectedElement.row}, Col {selectedElement.col}
                  </Text>
                </Stack>
              </Row>

              <Button
                variant="ghost"
                size="sm"
                onClick={() => setSelectedElement(null)}
              >
                Close Details
              </Button>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

