/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }

  // State management
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  // Compute derived values
  const isOutOfStock = !props.product.stock || props.product.stock <= 0;
  const stockStatus = props.product.stock && props.product.stock > 0
    ? props.product.stock <= 5 ? 'Low Stock' : 'In Stock'
    : 'Out of Stock';
  const stockBadgeVariant = props.product.stock && props.product.stock > 0 ? 'success' : 'error';

  const handleQuantityChange = useCallback((delta: number) => {
    setQuantity((prev) => {
      const newQty = prev + delta;
      const maxStock = props.product.stock || 1;
      return Math.max(1, Math.min(newQty, maxStock));
    });
  }, [props.product.stock]);

  const handleAddToCart = useCallback(() => {
    if (props.product.id) {
      addToCart({ productId: props.product.id, quantity });
      setQuantity(1);
    }
  }, [props.product.id, quantity, addToCart]);

  // Helper to render rating stars
  const renderStars = (rating: number | undefined) => {
    if (!rating) return null;
    const stars = [];
    for (let i = 1; i <= 5; i++) {
      stars.push(
        <Icon
          key={i}
          name={i <= Math.round(rating) ? 'star' : 'star'}
          size={16}
          color={i <= Math.round(rating) ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outlineVariant)'}
        />
      );
    }
    return <Row gap="var(--ggui-spacing-1)" align="center">{stars}</Row>;
  };

  const tabItems = [
    {
      key: 'description',
      label: 'Description',
      content: (
        <Stack gap="var(--ggui-spacing-4)">
          {props.product.description || 'No description available.'}
        </Stack>
      ),
    },
    {
      key: 'specifications',
      label: 'Specifications',
      content: (
        <Box padding="var(--ggui-spacing-4)">
          {Array.isArray(props.product.specifications) && props.product.specifications.length > 0 ? (
            <Table
              columns={[
                { key: 'spec', header: 'Specification', width: '50%' },
                { key: 'value', header: 'Value', width: '50%' },
              ]}
              data={props.product.specifications.map((spec: any, idx: number) => ({
                spec: typeof spec === 'object' ? spec.name || spec.key || `Spec ${idx + 1}` : `Spec ${idx + 1}`,
                value: typeof spec === 'object' ? spec.value || spec.description || '—' : String(spec),
              }))}
              striped
            />
          ) : (
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">No specifications available.</Text>
          )}
        </Box>
      ),
    },
    {
      key: 'reviews',
      label: 'Reviews',
      content: (
        <Stack gap="var(--ggui-spacing-4)">
          {Array.isArray(props.product.reviews) && props.product.reviews.length > 0 ? (
            props.product.reviews.map((review: any, idx: number) => (
              <Card key={idx} padding="var(--ggui-spacing-3)" shadow="sm" border>
                <Stack gap="var(--ggui-spacing-2)">
                  <Row gap="var(--ggui-spacing-2)" align="center" justify="between">
                    <Text variant="label" weight="semibold">{review.author || 'Anonymous'}</Text>
                    {renderStars(review.rating)}
                  </Row>
                  <Text variant="body">{review.text || review.content || ''}</Text>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                    {review.date ? new Date(review.date).toLocaleDateString() : ''}
                  </Text>
                </Stack>
              </Card>
            ))
          ) : (
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">No reviews yet.</Text>
          )}
        </Stack>
      ),
    },
  ];

  return (
