        <Row gap="var(--ggui-spacing-6)" align="start" justify="start" wrap>
          {/* Product image placeholder */}
          <Box
            background="var(--ggui-color-primary-100)"
            borderRadius="var(--ggui-shape-radius-lg)"
            padding="var(--ggui-spacing-8)"
            style={{ minWidth: '300px', width: '300px', height: '400px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
          >
            <Text variant="body" align="center" color="var(--ggui-color-primary-700)" weight="semibold">
              {props.product.name || 'Product Image'}
            </Text>
          </Box>

          {/* Product details column */}
          <Stack gap="var(--ggui-spacing-4)" align="stretch" style={{ flex: 1, minWidth: '280px' }}>
            <Stack gap="var(--ggui-spacing-2)">
              <Heading level={2}>{props.product.name || 'Product'}</Heading>
              <Row gap="var(--ggui-spacing-2)" align="center">
                {renderStars(props.product.rating)}
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  {props.product.rating ? `${props.product.rating.toFixed(1)}/5` : 'No rating'} ({props.product.reviewCount || 0} reviews)
                </Text>
              </Row>
            </Stack>

            <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-primary-600)">
              {props.product.currency || '$'}{props.product.price?.toFixed(2) || '0.00'}
            </Text>

            <Badge variant={stockBadgeVariant} size="md">
              {stockStatus}
            </Badge>
          </Stack>
        </Row>

        {/* Middle section: Tabs */}
