        {/* Bottom section: Quantity and Add to Cart */}
        <Stack gap="var(--ggui-spacing-4)" direction="horizontal" align="center" justify="start">
          <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
            <Button
              variant="outline"
              size="sm"
              onClick={() => handleQuantityChange(-1)}
              disabled={quantity <= 1}
            >
              −
            </Button>
            <Text variant="label" align="center" style={{ minWidth: '40px' }}>
              {quantity}
            </Text>
            <Button
              variant="outline"
              size="sm"
              onClick={() => handleQuantityChange(1)}
              disabled={quantity >= (props.product.stock || 1)}
            >
