  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage');

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message');
  const typing = useStream<StreamTyping>('typing');

  // State for messages and input
  const [messages, setMessages] = useState(props.messages || []);
  const [inputValue, setInputValue] = useState('');
  const [typingUsers, setTypingUsers] = useState<Set<string>>(new Set());
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Append new messages from stream
  useEffect(() => {
    if (message.latest) {
      setMessages(prev => [...prev, message.latest as StreamMessage]);
    }
  }, [message.latest]);

  // Handle typing indicator
  useEffect(() => {
    if (typing.latest) {
      const sender = typing.latest.sender || 'Unknown';
      if (typing.latest.active) {
        setTypingUsers(prev => new Set([...prev, sender]));
      } else {
        setTypingUsers(prev => {
          const next = new Set(prev);
          next.delete(sender);
          return next;
        });
      }
    }
  }, [typing.latest]);

  // Auto-scroll to bottom on new messages
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, typingUsers]);

  // Handle send message
  const handleSendMessage = useCallback(() => {
    if (inputValue.trim()) {
      const timestamp = new Date().toISOString();
      sendMessage({ text: inputValue, timestamp });
      setMessages(prev => [...prev, { sender: props.currentUser, text: inputValue, timestamp }]);
      setInputValue('');
    }
  }, [inputValue, props.currentUser, sendMessage]);

  // Handle Enter key in input
  const handleKeyDown = useCallback((e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  }, [handleSendMessage]);

  return (
    <Card shadow="md" radius="lg" padding="var(--ggui-spacing-4)" style={{ height: '100vh', display: 'flex', flexDirection: 'column' }}>
      <Stack gap="var(--ggui-spacing-4)" style={{ flex: 1, display: 'flex', flexDirection: 'column' }}>
        {/* Header */}
        <Box padding="var(--ggui-spacing-3)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
          <Row justify="between" align="center" gap="var(--ggui-spacing-3)">
            <Stack gap="var(--ggui-spacing-2)" align="start">
              <Heading level={3} color="var(--ggui-color-onSurface)">{props.title}</Heading>
              <Row gap="var(--ggui-spacing-2)" align="center">
                <Badge variant="primary" size="sm">{props.participantCount} participants</Badge>
                {typingUsers.size > 0 && (
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" style={{ fontStyle: 'italic' }}>
                    {Array.from(typingUsers).join(', ')} {'is ' + (typingUsers.size === 1 ? 'typing' : 'are typing')}...
                  </Text>
                )}
              </Row>
            </Stack>
          </Row>
        </Box>

        {/* Message List */}
        <Stack
          gap="var(--ggui-spacing-3)"
          style={{
            flex: 1,
            overflowY: 'auto',
            padding: 'var(--ggui-spacing-3)',
            background: 'var(--ggui-color-surface)',
            borderRadius: 'var(--ggui-shape-radius-md)',
            border: '1px solid var(--ggui-color-outlineVariant)',
          }}
        >
          {messages.length === 0 ? (
            <Box style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100%' }}>
              <Text color="var(--ggui-color-onSurfaceVariant)" variant="caption">No messages yet. Start the conversation!</Text>
            </Box>
          ) : (
            messages.map((msg, index) => {
              const isCurrentUser = msg.sender === props.currentUser;
              const sameAsPrev = index > 0 && messages[index - 1]?.sender === msg.sender;
              return (
                <Box key={index} style={{ display: 'flex', justifyContent: isCurrentUser ? 'flex-end' : 'flex-start' }}>
                  <Card
                    padding="var(--ggui-spacing-3)"
                    shadow="none"
                    radius="md"
                    border={false}
                    style={{
                      maxWidth: '70%',
                      background: isCurrentUser ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)',
                    }}
                  >
                    {!sameAsPrev && (
                      <Text
                        variant="label"
                        color={isCurrentUser ? 'white' : 'var(--ggui-color-onSurfaceVariant)'}
                        size="sm"
                      >
                        {msg.sender}
                      </Text>
                    )}
                    <Text
                      color={isCurrentUser ? 'white' : 'var(--ggui-color-onSurface)'}
                      variant="body"
                    >
                      {msg.text}
                    </Text>
                    <Text
                      variant="caption"
                      color={isCurrentUser ? 'rgba(255, 255, 255, 0.7)' : 'var(--ggui-color-onSurfaceVariant)'}
                      size="xs"
                      style={{ marginTop: 'var(--ggui-spacing-1)' }}
                    >
                      {msg.timestamp ? new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : ''}
                    </Text>
                  </Card>
                </Box>
              );
            })
          )}
          <div ref={messagesEndRef} />
        </Stack>

        {/* Input Area */}
        <Row gap="var(--ggui-spacing-2)" align="end">
          <TextArea
            label="Message"
            value={inputValue}
            onChange={setInputValue}
            onKeyDown={handleKeyDown}
            placeholder="Type your message..."
            rows={3}
            style={{ flex: 1, display: 'flex', flexDirection: 'column' }}
          />
          <Button
            variant="primary"
            size="md"
            onClick={handleSendMessage}
            disabled={!inputValue.trim()}
            style={{ marginBottom: 'var(--ggui-spacing-3)' }}
          >
            Send
          </Button>
         </Row>
       </Stack>
     </Card>
   );
}

