                          : 'var(--ggui-color-error-500)'
                      }`,
                      animation: `ggui-flash 600ms ease-out`,
                      '--ggui-flash-color': flashColor,
                    } as React.CSSProperties}
                  >
                    <Stack gap="var(--ggui-spacing-4)">
                      {/* Ticker Symbol */}
                      <Text
                        variant="label"
                        weight="bold"
                        size="2xl"
                        color={isPositive ? 'var(--ggui-color-success-500)' : 'var(--ggui-color-error-500)'}
                      >
                        {stock.symbol || 'N/A'}
                      </Text>

                      {/* Company Name */}
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                        {stock.name || 'Unknown'}
                      </Text>

                      <Spacer size={1} />

                      {/* Price */}
                      <Text variant="body" weight="semibold">
                        ${(stock.price ?? 0).toFixed(2)}
                      </Text>

                      {/* Change and Percentage */}
                      <Row gap="var(--ggui-spacing-2)" align="center">
                        <Icon
                          name={isPositive ? 'trending-up' : 'trending-down'}
                          size={16}
                          color={isPositive ? 'var(--ggui-color-success-500)' : 'var(--ggui-color-error-500)'}
                        />
                        <Text
                          variant="body"
                          color={isPositive ? 'var(--ggui-color-success-500)' : 'var(--ggui-color-error-500)'}
                        >
                          {isPositive ? '+' : ''}{(stock.change ?? 0).toFixed(2)} ({(stock.changePercent ?? 0).toFixed(2)}%)
                        </Text>
                      </Row>
                    </Stack>
                  </Card>
                </Box>
              );
            })}
          </Box>
        )}
      </Stack>
    </Container>
  );
