  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





export default function Component(props: Props) {
  // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete');

  // State management
  const [currentStep, setCurrentStep] = useState<1 | 2 | 3>(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile.name || '',
    email: props.initialProfile.email || '',
    avatar: props.initialProfile.avatar || props.avatarOptions[0] || '',
    role: props.initialProfile.role || '',
    emailNotifications: props.initialProfile.emailNotifications ?? true,
    theme: props.initialProfile.theme || 'light',
  });

  // Validation state
  const [errors, setErrors] = useState({
    name: '',
    email: '',
  });

  // Validation helpers
  const validateEmail = (email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };

  const validateStep1 = (): boolean => {
    const newErrors = { name: '', email: '' };
    let isValid = true;

    if (!formData.name.trim()) {
      newErrors.name = 'Name is required';
      isValid = false;
    }

    if (!formData.email.trim()) {
      newErrors.email = 'Email is required';
      isValid = false;
    } else if (!validateEmail(formData.email)) {
      newErrors.email = 'Please enter a valid email address';
      isValid = false;
    }

    setErrors(newErrors);
    return isValid;
  };

  // Event handlers
  const handleInputChange = (field: string, value: string) => {
    setFormData(prev => ({ ...prev, [field]: value }));
    // Clear error on change
    if (field === 'name' || field === 'email') {
      setErrors(prev => ({ ...prev, [field]: '' }));
    }
  };

  const handleNext = () => {
    if (currentStep === 1) {
      if (!validateStep1()) return;
    }
    setCurrentStep((prev) => Math.min(prev + 1, 3) as 1 | 2 | 3);
  };

  const handleBack = () => {
    setCurrentStep((prev) => Math.max(prev - 1, 1) as 1 | 2 | 3);
  };

  const handleComplete = () => {
    complete({
      name: formData.name,
      email: formData.email,
      avatar: formData.avatar,
      role: formData.role,
      emailNotifications: formData.emailNotifications,
      theme: formData.theme,
    });
  };

  const isStep1Valid = formData.name.trim() && formData.email.trim() && validateEmail(formData.email);

  // Convert roleOptions to SelectOption format
  const roleSelectOptions = props.roleOptions.map(role => ({ value: role, label: role }));

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* Header */}
        <Stack gap="var(--ggui-spacing-4)">
          <Heading level={1}>Complete Your Profile</Heading>
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
            Step {currentStep} of 3
          </Text>

          {/* Progress bar */}
          <Progress
            value={currentStep * 33.33}
            max={100}
            size="md"
            variant="default"
          />
        </Stack>

        {/* Step 1: Profile Setup */}
        {currentStep === 1 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)">
            <Stack gap="var(--ggui-spacing-6)">
              {/* Step indicator */}
              <Stack gap="var(--ggui-spacing-2)">
                <Heading level={2}>Profile Setup</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  Set up your basic profile information
                </Text>
              </Stack>

              {/* Name input */}
              <Input
                label="Full Name"
                placeholder="Enter your full name"
                value={formData.name}
                onChange={(value) => handleInputChange('name', value)}
                error={errors.name}
                required
              />

              {/* Email input */}
              <Input
                label="Email Address"
                type="email"
                placeholder="you@example.com"
                value={formData.email}
                onChange={(value) => handleInputChange('email', value)}
                error={errors.email}
                required
              />

              {/* Avatar selection */}
              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="label">Select Avatar</Text>
                <Row gap="var(--ggui-spacing-3)" align="center">
                  {props.avatarOptions.map((avatar) => (
                    <Card
                      key={avatar}
                      as={Clickable}
                      onClick={() => handleInputChange('avatar', avatar)}
                      padding="var(--ggui-spacing-2)"
                      border={formData.avatar === avatar}
                      shadow={formData.avatar === avatar ? 'md' : 'sm'}
                      style={{
                        cursor: 'pointer',
                        borderColor: formData.avatar === avatar ? 'var(--ggui-color-primary-600)' : undefined,
                        borderWidth: formData.avatar === avatar ? '2px' : undefined,
                      }}
                    >
                      <Text size="3xl">{avatar}</Text>
                    </Card>
                  ))}
                </Row>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 2: Preferences */}
        {currentStep === 2 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)">
            <Stack gap="var(--ggui-spacing-6)">
              {/* Step indicator */}
              <Stack gap="var(--ggui-spacing-2)">
                <Heading level={2}>Preferences</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  Customize your experience
                </Text>
              </Stack>

              {/* Role selection */}
              <Select
                label="Role"
                value={formData.role}
                onChange={(value) => handleInputChange('role', value)}
                options={roleSelectOptions}
                placeholder="Select your role"
              />

              {/* Notification toggle */}
              <Toggle
                label="Email Notifications"
                checked={formData.emailNotifications}
                onChange={(checked) => setFormData(prev => ({ ...prev, emailNotifications: checked }))}
                size="md"
              />

              {/* Theme preference */}
              <Toggle
                label="Dark Theme"
                checked={formData.theme === 'dark'}
                onChange={(checked) => setFormData(prev => ({ ...prev, theme: checked ? 'dark' : 'light' }))}
                size="md"
              />
            </Stack>
          </Card>
        )}

        {/* Step 3: Review & Confirm */}
        {currentStep === 3 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)">
            <Stack gap="var(--ggui-spacing-6)">
              {/* Step indicator */}
              <Stack gap="var(--ggui-spacing-2)">
                <Heading level={2}>Review & Confirm</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  Please review your information before completing setup
                </Text>
