import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [touchedName, setTouchedName] = useState(false);
  const [touchedEmail, setTouchedEmail] = useState(false);
  const totalSteps = 5;

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const nameError = touchedName && !name.trim() ? 'Name is required.' : '';
  const emailError = touchedEmail && !email.trim()
    ? 'Email is required.'
    : touchedEmail && !emailRegex.test(email)
      ? 'Please enter a valid email address.'
      : '';

  const isStep1Valid = name.trim().length > 0 && emailRegex.test(email);
  const isStep2Valid = satisfaction !== '';
  const canGoNext = (step === 1 && isStep1Valid) || (step === 2 && isStep2Valid) || step === 3 || step === 4;

  const satisfactionOptions = useMemo(() => {
    if (!props.satisfactionLabels || props.satisfactionLabels.length === 0) {
      return [];
    }
    return props.satisfactionLabels.map((label, index) => ({
      value: String(index + 1),
      label,
    }));
  }, [props.satisfactionLabels]);

  const toggleFeature = useCallback((feature: string, checked: boolean) => {
    setFeatures((prev) => {
      if (checked) {
        if (prev.includes(feature)) return prev;
        return [...prev, feature];
      }
      return prev.filter((item) => item !== feature);
    });
  }, []);

  const goNext = useCallback(() => {
    if (step === 1) {
      setTouchedName(true);
      setTouchedEmail(true);
      if (!isStep1Valid) return;
    }
    if (step === 2 && !isStep2Valid) return;
    if (step < totalSteps) setStep((prev) => prev + 1);
  }, [step, isStep1Valid, isStep2Valid]);

  const goBack = useCallback(() => {
    if (step > 1) setStep((prev) => prev - 1);
  }, [step]);

  const handleSubmit = useCallback(() => {
    const payload: ActionSubmitPayload = {
      name: name.trim(),
      email: email.trim(),
      satisfaction: Number(satisfaction),
      features,
      comments,
    };
    submit(payload);
  }, [name, email, satisfaction, features, comments, submit]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="sm" border>
          <Stack gap="var(--ggui-spacing-3)">
            <Row justify="between" align="center">
              <Heading level={3} color="var(--ggui-color-onSurface)">
                Multi-Step Survey
              </Heading>
              <Badge variant="primary">Step {step} of {totalSteps}</Badge>
            </Row>
            <Progress value={(step / totalSteps) * 100} max={100} size="md" variant="default" />
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              Please complete each step to submit your survey response.
            </Text>
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm" border>
          {step === 1 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Step 1: Contact Information</Heading>
              <Input
                label="Name"
                value={name}
                onChange={setName}
                required
                error={nameError || undefined}
                placeholder="Enter your full name"
              />
              <Input
                label="Email"
                type="email"
                value={email}
                onChange={setEmail}
                required
                error={emailError || undefined}
                placeholder="you@example.com"
              />
            </Stack>
          )}

          {step === 2 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Step 2: Satisfaction Rating</Heading>
              {satisfactionOptions.length === 0 ? (
                <Alert variant="warning" title="No rating labels available">
                  Satisfaction labels were not provided.
                </Alert>
              ) : (
                <RadioGroup
                  label="How satisfied are you?"
                  value={satisfaction}
                  onChange={setSatisfaction}
                  options={satisfactionOptions}
                  direction="vertical"
                />
              )}
            </Stack>
          )}

          {step === 3 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Step 3: Feature Interests</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Select all features you are interested in.
              </Text>
              {!props.featureOptions || props.featureOptions.length === 0 ? (
                <Alert variant="info" title="No feature options available">
                  Feature options were not provided.
                </Alert>
              ) : (
                <Stack gap="var(--ggui-spacing-2)">
                  {props.featureOptions.map((feature) => (
                    <Checkbox
                      key={feature}
                      label={feature}
                      checked={features.includes(feature)}
                      onChange={(checked) => toggleFeature(feature, checked)}
                    />
                  ))}
                </Stack>
              )}
            </Stack>
          )}

          {step === 4 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Step 4: Additional Comments</Heading>
              <TextArea
                label="Comments (optional)"
                value={comments}
                onChange={setComments}
                placeholder="Share any additional feedback..."
                maxLength={500}
                showCount
                rows={6}
              />
            </Stack>
          )}

          {step === 5 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Final Review</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Please review your responses before submitting.
              </Text>
              <Divider margin="var(--ggui-spacing-2)" />
              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="label">Name</Text>
                <Text>{name || '—'}</Text>
                <Text variant="label">Email</Text>
                <Text>{email || '—'}</Text>
                <Text variant="label">Satisfaction</Text>
                <Text>
                  {satisfaction
                    ? props.satisfactionLabels[Number(satisfaction) - 1] || `Rating ${satisfaction}`
                    : '—'}
                </Text>
                <Text variant="label">Interested Features</Text>
                <Text>{features.length > 0 ? features.join(', ') : 'None selected'}</Text>
                <Text variant="label">Comments</Text>
                <Text>{comments.trim() ? comments : 'No additional comments'}</Text>
              </Stack>
            </Stack>
          )}
        </Card>

        <Row justify="between" align="center">
          <Button variant="outline" disabled={step === 1} onClick={goBack}>
            Back
          </Button>

          {step < totalSteps ? (
            <Button
              variant="primary"
              disabled={!canGoNext || (step === 2 && satisfactionOptions.length === 0)}
              onClick={goNext}
            >
              Next
            </Button>
          ) : (
            <Button variant="primary" onClick={handleSubmit}>
              Submit Survey
            </Button>
          )}
        </Row>
      </Stack>
    </Container>

  );
}

