        prev.map((task) => {
          if ((task.id || '') !== taskId) return task;
          return { ...task, column: nextColumn };
        }),
      );
      try {
        taskUpdate({ action: 'move', taskId, data: { column: nextColumn } });
        setActionError('');
      } catch (error) {
        setActionError('Failed to move task. Please try again.');
      }
    },
    [taskUpdate],
  );

  const saveEdit = useCallback(
    (taskId: string) => {
      const trimmed = editingTitle.trim();
      if (!trimmed) return;
      setTasksState((prev) => prev.map((task) => ((task.id || '') === taskId ? { ...task, title: trimmed } : task)));
      const editedTask = safeTasks.find((task) => (task.id || '') === taskId);
      try {
        taskUpdate({
          action: 'edit',
          taskId,
          data: {
            column: editedTask?.column || '',
            title: trimmed,
            priority: editedTask?.priority || 'low',
            assignee: editedTask?.assignee || '',
            dueDate: editedTask?.dueDate || '',
          },
        });
        setActionError('');
      } catch (error) {
        setActionError('Failed to edit task. Please try again.');
      }
      setEditingTaskId('');
      setEditingTitle('');
    },
    [editingTitle, safeTasks, taskUpdate],
  );

  const createTask = useCallback(
    (columnId: string) => {
      const title = (newTitleByColumn[columnId] || '').trim();
      const priority = newPriorityByColumn[columnId] || 'low';
      if (!title) return;
      const id = `task-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
      const newTask = { id, title, priority, assignee: '', column: 'todo', dueDate: '' };
      setTasksState((prev) => [...prev, newTask]);
      try {
        taskUpdate({
          action: 'create',
          taskId: id,
          data: {
            column: 'todo',
            title,
            priority,
            assignee: '',
            dueDate: '',
          },
        });
        setActionError('');
      } catch (error) {
        setActionError('Failed to create task. Please try again.');
      }
      setShowAddByColumn((prev) => ({ ...prev, [columnId]: false }));
      setNewTitleByColumn((prev) => ({ ...prev, [columnId]: '' }));
      setNewPriorityByColumn((prev) => ({ ...prev, [columnId]: 'low' }));
    },
    [newPriorityByColumn, newTitleByColumn, taskUpdate],
  );

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-4)">
        <Card padding="var(--ggui-spacing-4)" border shadow="sm">
          <Row justify="between" align="center">
            <Heading level={2}>Team Kanban Board</Heading>
            <Row gap="var(--ggui-spacing-3)">
              <Badge variant="primary">Total: {totalCount}</Badge>
              <Badge variant="success">Completed: {completedCount}</Badge>
              <Badge variant={taskChanged.latest ? 'warning' : 'default'}>
                Updates: {taskChanged.all.length}
              </Badge>
            </Row>
          </Row>
        </Card>

        {actionError ? (
          <Alert variant="error" title="Update failed">
            {actionError}
          </Alert>
        ) : null}

        {safeColumns.length === 0 ? (
          <Alert variant="warning" title="No columns">
            No columns were provided in props.columns.
          </Alert>
        ) : (
          <Row gap="var(--ggui-spacing-4)" align="start">
            {safeColumns.map((column) => {
              const columnId = column.id || '';
              const columnTasks = safeTasks.filter((task) => (task.column || '') === columnId);
              return (
                <Card
                  key={columnId || column.name || Math.random().toString(36)}
                  padding="var(--ggui-spacing-4)"
                  border
                  shadow="sm"
                >
                  <Stack gap="var(--ggui-spacing-3)">
                    <Row justify="between" align="center">
                      <Heading level={3}>{column.name || 'Untitled'}</Heading>
                      <Badge variant="default">{columnTasks.length}</Badge>
                    </Row>

                    <Stack gap="var(--ggui-spacing-3)">
                      {columnTasks.length === 0 ? (
                        <Text color="var(--ggui-color-onSurfaceVariant)">No tasks yet</Text>
                      ) : (
                        columnTasks.map((task) => {
                          const taskId = task.id || '';
                          const currentColumn = task.column || '';
                          const moveOptions = safeColumns
                            .filter((c) => (c.id || '') !== currentColumn)
                            .map((c) => ({ value: c.id || '', label: c.name || 'Unnamed' }));

                          return (
                            <Card key={taskId} padding="var(--ggui-spacing-3)" border shadow="none">
                              <Stack gap="var(--ggui-spacing-2)">
                                {editingTaskId === taskId ? (
                                  <Row gap="var(--ggui-spacing-2)" align="end">
                                    <Box>
                                      <Input label="Edit task title" value={editingTitle} onChange={setEditingTitle} />
                                    </Box>
                                    <Button size="sm" onPress={() => saveEdit(taskId)}>Save</Button>
                                    <Button
                                      variant="ghost"
                                      size="sm"
                                      onPress={() => {
                                        setEditingTaskId('');
                                        setEditingTitle('');
                                      }}
                                    >
                                      Cancel
                                    </Button>
                                  </Row>
                                ) : (
                                  <Row justify="between" align="center">
                                    <Text
                                      as={Clickable}
                                      onClick={() => {
                                        setEditingTaskId(taskId);
                                        setEditingTitle(task.title || '');
                                      }}
                                      weight="medium"
                                    >
                                      {task.title || 'Untitled task'}
                                    </Text>
                                    <Button
                                      variant="ghost"
                                      size="sm"
                                      onPress={() => {
                                        setEditingTaskId(taskId);
                                        setEditingTitle(task.title || '');
                                      }}
                                    >
                                      Edit
                                    </Button>
                                  </Row>
                                )}

                                <Row gap="var(--ggui-spacing-2)" align="center">
                                  <Badge variant={getPriorityVariant(task.priority)}>{task.priority || 'low'}</Badge>
                                  {task.assignee ? <Avatar name={task.assignee} size="xs" /> : <Avatar name="Unassigned" size="xs" />}
                                  {task.dueDate ? <Text variant="caption">Due: {task.dueDate}</Text> : <Text variant="caption">No due date</Text>}
                                </Row>

                                <Select
                                  label="Move task"
                                  value=""
                                  onChange={(value) => {
                                    if (value) moveTask(taskId, value);
                                  }}
                                  placeholder="Move to..."
                                  options={moveOptions}
                                />
                              </Stack>
                            </Card>
                          );
                        })
                      )}
                    </Stack>

                    {showAddByColumn[columnId] ? (
                      <Card padding="var(--ggui-spacing-3)" border shadow="none">
                        <Stack gap="var(--ggui-spacing-2)">
                          <Input
                            label="Task title"
