                              Cancel
                            </Button>
                          </Row>
                        </Stack>
                      </Card>
                    ) : (
                      <Button variant="ghost" onPress={() => setShowAddByColumn((prev) => ({ ...prev, [columnId]: true }))}>
                        + Add Task
                      </Button>
                    )}
                  </Stack>
                </Card>
              );
            })}
          </Row>
        )}

        {safeColumns.length > 0 && totalCount === 0 ? (
          <Alert variant="info" title="No tasks yet">
            Your board is empty. Add your first task in any column to get started.
          </Alert>
        ) : null}
      </Stack>
    </Container>

  );
}

