    return (props.product.specifications ?? []).map((item, index) => {
      if (item && typeof item === 'object') {
        const candidate = item as Record<string, unknown>;
        const key = String(candidate.key ?? candidate.name ?? candidate.label ?? `Spec ${index + 1}`);
        const value = String(candidate.value ?? candidate.detail ?? candidate.spec ?? '—');
        return { key, value, rowKey: `${key}-${index}` };
      }
      return { key: `Spec ${index + 1}`, value: String(item ?? '—'), rowKey: `spec-${index}` };
    });
  }, [props.product.specifications]);

  const normalizedReviews = useMemo(() => {
    return (props.product.reviews ?? []).map((review, index) => {
      const fallback = {
        author: `Reviewer ${index + 1}`,
        rating: 0,
        text: 'No review text provided.',
        date: 'Unknown date',
      };
      if (review && typeof review === 'object') {
