          date: String(candidate.date ?? candidate.createdAt ?? fallback.date),
        };
      }
      return fallback;
    });
  }, [props.product.reviews]);

  const handleIncrement = useCallback(() => {
    setQuantity((prev) => {
      const max = Math.max(1, props.product.stock ?? 1);
      if (prev >= max) {
        return max;
      }
      return prev + 1;
    });
  }, [props.product.stock]);

  const handleDecrement = useCallback(() => {
    setQuantity((prev) => {
      if (prev <= 1) {
        return 1;
      }
      return prev - 1;
    });
  }, []);

  const handleAddToCart = useCallback(() => {
    if (!props.product.id || !inStock) {
