                  justifyContent: 'center',
                  border: '1px solid var(--ggui-color-primary-200)',
                }}
              >
                <Heading level={3} color="var(--ggui-color-primary-700)" align="center">
                  {props.product.name ?? 'Unnamed Product'}
                </Heading>
              </Box>

