                <Heading level={2}>{props.product.name ?? 'Unnamed Product'}</Heading>
                <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-primary-700)">
                  {formattedPrice}
                </Text>

                <Row gap="var(--ggui-spacing-1)" align="center" aria-label={`Rating: ${clampedRating} out of 5`}>
                  {Array.from({ length: 5 }).map((_, index) => (
                    <Icon
                      key={`star-${index}`}
                      name={index < clampedRating ? 'star' : 'star-off'}
                      color={index < clampedRating ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outline)'}
                      size={18}
                      aria-hidden
                    />
                  ))}
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                    ({props.product.reviewCount ?? normalizedReviews.length})
