export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  const [allMessages, setAllMessages] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>(props.messages ?? []);
  const [draft, setDraft] = useState<string>('');
  const [activeTypist, setActiveTypist] = useState<string>('');
  const [sendError, setSendError] = useState<string>('');
  const endRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    setAllMessages(props.messages ?? []);
  }, [props.messages]);

  useEffect(() => {
    if (!message.latest) return;
    setAllMessages((prev) => [...prev, message.latest as StreamMessage]);
  }, [message.latest]);

  useEffect(() => {
    if (!typing.latest) return;
    if (typing.latest.active && typing.latest.sender && typing.latest.sender !== props.currentUser) {
      setActiveTypist(typing.latest.sender);
    } else {
      setActiveTypist('');
    }
  }, [typing.latest, props.currentUser]);

  useEffect(() => {
    if (endRef.current) {
      endRef.current.scrollIntoView({ behavior: 'smooth', block: 'end' });
    }
  }, [allMessages.length, activeTypist]);

  const groupedMessages = useMemo(() => {
    const groups: Array<{ sender: string; items: Array<{ sender?: string; text?: string; timestamp?: string }> }> = [];
    (allMessages ?? []).forEach((msg) => {
      const senderName = msg.sender && msg.sender.trim() ? msg.sender : 'Unknown';
      const lastGroup = groups[groups.length - 1];
      if (lastGroup && lastGroup.sender === senderName) {
        lastGroup.items.push(msg);
      } else {
        groups.push({ sender: senderName, items: [msg] });
      }
    });
    return groups;
  }, [allMessages]);

  const formatTimestamp = useCallback((value?: string) => {
    if (!value) return '—';
    const date = new Date(value);
    if (Number.isNaN(date.getTime())) return '—';
    return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  }, []);

  const handleSend = useCallback(() => {
    const trimmed = draft.trim();
    if (!trimmed) return;
    const ts = new Date().toISOString();
    try {
      sendMessage({ text: trimmed, timestamp: ts });
      setAllMessages((prev) => [...prev, { sender: props.currentUser, text: trimmed, timestamp: ts }]);
      setDraft('');
      setSendError('');
    } catch (_error) {
      setSendError('Failed to send message. Please try again.');
    }
  }, [draft, sendMessage, props.currentUser]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card
        padding="var(--ggui-spacing-4)"
        shadow="sm"
        border
      >
