              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant">
                Real-time conversation
              </Text>
            </Stack>
            <Badge variant="primary" size="md">{props.participantCount} participants</Badge>
          </Row>

          {activeTypist ? (
            <Alert variant="info" title="Typing">
              <Text is="span" variant="bodySmall" color="var(--ggui-color-onSurface)">
                {activeTypist} is typing…
              </Text>
            </Alert>
          ) : null}

          <Box
            padding="var(--ggui-spacing-3)"
            background="var(--ggui-color-surface)"
            borderRadius="var(--ggui-shape-radius-md)"
          >
            <Stack gap="var(--ggui-spacing-3)">
              <Box
                padding="var(--ggui-spacing-2)"
                background="var(--ggui-color-surfaceVariant)"
                borderRadius="var(--ggui-shape-radius-md)"
              >
                <Box style={{ maxHeight: '60vh', overflowY: 'auto' }}>
                  <Stack gap="var(--ggui-spacing-2)">
                    {groupedMessages.length === 0 ? (
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                        No messages yet.
                      </Text>
                    ) : (
                      groupedMessages.map((group, groupIndex) => {
                        const isCurrentUser = group.sender === props.currentUser;
                        return (
                          <Stack
                            key={`${group.sender}-${groupIndex}`}
                            gap="var(--ggui-spacing-1)"
                            align={isCurrentUser ? 'end' : 'start'}
                          >
                              <Stack gap="var(--ggui-spacing-1)" align={isCurrentUser ? 'end' : 'start'}>
                                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                  {group.sender}
                                </Text>
                                {(group.items ?? []).map((item, itemIndex) => (
                                  <Box
                                    key={`${group.sender}-${groupIndex}-${item.timestamp ?? 'no-time'}-${itemIndex}`}
>
                                    <Box
                                      padding="var(--ggui-spacing-2)"
                                      background={isCurrentUser ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                                      borderRadius="var(--ggui-shape-radius-md)"
                                    >
                                      <Stack gap="var(--ggui-spacing-1)">
                                        <Text
                                          variant="bodySmall"
                                          color={isCurrentUser ? 'var(--ggui-color-surface)' : 'var(--ggui-color-onSurface)'}
                                        >
                                          {item.text && item.text.trim() ? item.text : ' '}
                                        </Text>
                                        <Text
                                          variant="caption"
                                          color={isCurrentUser ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-onSurfaceVariant)'}
                                        >
                                          {formatTimestamp(item.timestamp)}
                                        </Text>
                                      </Stack>
                                    </Box>
                                  </Box>
                                ))}
                              </Stack>
                            </Stack>

                        );
                      })
                    )}
                    <Box><div ref={endRef} /></Box>
                  </Stack>
                </Box>
              </Box>

              <Divider margin="var(--ggui-spacing-2)" color="var(--ggui-color-outlineVariant)" />

              {sendError ? (
                <Alert variant="error" title="Send failed">
                  <Text variant="bodySmall" color="var(--ggui-color-onSurface)">{sendError}</Text>
                </Alert>
              ) : null}
              <Row gap="var(--ggui-spacing-2)" align="end">
                <Box padding="0 var(--ggui-spacing-1) 0 0">
                  <Input
                    label="Message"
                    placeholder="Type your message..."
                    value={draft}
                    onChange={setDraft}
                    onKeyDown={(event) => {
                      if (event.key === 'Enter') {
                        event.preventDefault();
                        handleSend();
                      }
                    }}
                  />
                </Box>
                <Button variant="primary" onClick={handleSend} disabled={!draft.trim()}>
                  Send
                </Button>
              </Row>
            </Stack>
          </Box>
        </Stack>
      </Card>
    </Container>

  );
}

