interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update
  const [stockMap, setStockMap] = useState<Record<string, { symbol: string; name: string; price: number; change: number; changePercent: number }>>({});
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [now, setNow] = useState<Date>(new Date());
  const [flashMap, setFlashMap] = useState<Record<string, number>>({});

  useEffect(() => {
    const initial: Record<string, { symbol: string; name: string; price: number; change: number; changePercent: number }> = {};
    (props.stocks || []).forEach((stock) => {
      const symbol = stock.symbol || 'N/A';
      initial[symbol] = {
        symbol,
        name: stock.name || 'Unknown Company',
        price: typeof stock.price === 'number' ? stock.price : 0,
        change: typeof stock.change === 'number' ? stock.change : 0,
        changePercent: typeof stock.changePercent === 'number' ? stock.changePercent : 0,
      };
    });
    setStockMap(initial);
  }, [props.stocks]);

  useEffect(() => {
    const timer = setInterval(() => {
      setNow(new Date());
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    if (!priceUpdate.all || priceUpdate.all.length === 0) {
      return;
    }
    const latestEvent = priceUpdate.all[priceUpdate.all.length - 1];
    const updatesCandidate = (latestEvent as unknown as { updates?: StreamPriceUpdate[] }).updates;
    const updates = Array.isArray(updatesCandidate)
      ? updatesCandidate
      : [latestEvent].filter(Boolean) as StreamPriceUpdate[];

    const validUpdates = updates.filter((update) => Boolean(update?.symbol));
    if (validUpdates.length === 0) {
      return;
    }

    setStockMap((prev) => {
      const next = { ...prev };
      validUpdates.forEach((update) => {
        const symbol = update.symbol || 'N/A';
        const existing = next[symbol] || { symbol, name: 'Unknown Company', price: 0, change: 0, changePercent: 0 };
        next[symbol] = {
          ...existing,
          price: typeof update.price === 'number' ? update.price : existing.price,
          change: typeof update.change === 'number' ? update.change : existing.change,
          changePercent: typeof update.changePercent === 'number' ? update.changePercent : existing.changePercent,
        };
      });
      return next;
    });

    const updatedAt = new Date();
    setLastUpdated(updatedAt);
    setFlashMap((prev) => {
      const next = { ...prev };
      validUpdates.forEach((update) => {
        if (update.symbol) {
          next[update.symbol] = updatedAt.getTime();
        }
      });
      return next;
    });
  }, [priceUpdate.all]);

  const stocksList = useMemo(() => Object.values(stockMap), [stockMap]);

  const formatCurrency = useCallback((value: number) => `$${value.toFixed(2)}`, []);
  const formatSigned = useCallback((value: number) => `${value >= 0 ? '+' : ''}${value.toFixed(2)}`, []);
  const formatPercent = useCallback((value: number) => `${value >= 0 ? '+' : ''}${value.toFixed(2)}%`, []);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-4)" shadow="sm" border>
          <Row justify="between" align="center" wrap>
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={1} color="var(--ggui-color-onSurface)">
                Market Watch
              </Heading>
              <Box role="status" aria-live="polite">
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  Last Updated: {now.toLocaleTimeString()}
                </Text>
              </Box>
            </Stack>
            <Stack gap="var(--ggui-spacing-1)" align="end">
              <Badge
                variant={
                  marketStatus.latest?.status === 'open'
                    ? 'success'
                    : marketStatus.latest?.status === 'closed'
                      ? 'error'
                      : 'warning'
                }
              >
                {marketStatus.latest?.status || 'status unavailable'}
              </Badge>
              <Box role="status" aria-live="polite">
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  Feed: {lastUpdated.toLocaleTimeString()}
                </Text>
              </Box>
            </Stack>
          </Row>
        </Card>

        {stocksList.length === 0 ? (
          <Alert variant="info" title="No stocks available">
            Waiting for stock data.
          </Alert>
        ) : (
          <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
            {stocksList.map((stock) => {
              const isPositive = stock.change >= 0;
              const borderColor = isPositive ? 'var(--ggui-color-success-500)' : 'var(--ggui-color-error-500)';
              const textColor = isPositive ? 'var(--ggui-color-success-700)' : 'var(--ggui-color-error-700)';
              const shouldFlash = flashMap[stock.symbol] && Date.now() - flashMap[stock.symbol] < 900;

              return (
                <Card
                  key={stock.symbol}
                  padding="var(--ggui-spacing-4)"
                  shadow="sm"
                  border
                >
                  <Box
                    background={shouldFlash ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)'}
                    borderRadius="var(--ggui-shape-radius-md)"
                    padding="var(--ggui-spacing-2)"
                  >
                    <Stack gap="var(--ggui-spacing-2)">
                      <Row justify="between" align="start">
                        <Stack gap="var(--ggui-spacing-1)">
                          <Text size="2xl" weight="bold" color="var(--ggui-color-onSurface)">
                            {stock.symbol}
                          </Text>
                          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                            {stock.name}
                          </Text>
                        </Stack>
                        <Badge variant={isPositive ? 'success' : 'error'}>
                          {isPositive ? 'UP' : 'DOWN'}
                        </Badge>
                      </Row>

                      <Divider margin="var(--ggui-spacing-2)" color="var(--ggui-color-outlineVariant)" />

                      <Box role="status" aria-live="polite">
                        <Text size="xl" weight="semibold" color="var(--ggui-color-onSurface)">
                          {formatCurrency(stock.price)}
                        </Text>
                      </Box>
                      <Row justify="between" align="center">
                        <Text variant="label" color={textColor}>
                          {formatSigned(stock.change)}
                        </Text>
                        <Text
                          variant="label"
                          color={textColor}
                        >
                          <Text is="span" variant="label" color={textColor} aria-hidden="true">
                            {isPositive ? '▲' : '▼'}
                          </Text>{' '}
                          {isPositive ? 'up' : 'down'} {formatPercent(stock.changePercent)}
                        </Text>
                      </Row>

                      <Box
                        background="var(--ggui-color-surfaceVariant)"
                        borderRadius="var(--ggui-shape-radius-sm)"
                        padding="var(--ggui-spacing-1)"
                      >
                        <Text variant="caption" color={borderColor}>
                          Real-time movement tracked from live stream updates.
                        </Text>
                      </Box>
                    </Stack>
                  </Box>
                </Card>
              );
            })}
          </CardGrid>
        )}
      </Stack>
    </Container>
  );
}

