/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding
  const avatars = useMemo(() => (props.avatarOptions && props.avatarOptions.length > 0 ? props.avatarOptions.slice(0, 4) : ['😀', '🧑‍💻', '🎨', '🚀']), [props.avatarOptions]);
  const roles = useMemo(() => (props.roleOptions && props.roleOptions.length > 0 ? props.roleOptions : ['Developer', 'Designer', 'Manager', 'Other']), [props.roleOptions]);
  const [step, setStep] = useState(1);
  const [name, setName] = useState(props.initialProfile?.name ?? '');
  const [email, setEmail] = useState(props.initialProfile?.email ?? '');
  const [avatar, setAvatar] = useState(props.initialProfile?.avatar ?? (avatars[0] ?? '😀'));
  const [role, setRole] = useState(props.initialProfile?.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile?.emailNotifications ?? true);
  const [theme, setTheme] = useState(props.initialProfile?.theme === 'dark' ? 'dark' : 'light');

  useEffect(() => {
    setName(props.initialProfile?.name ?? '');
    setEmail(props.initialProfile?.email ?? '');
    setAvatar(props.initialProfile?.avatar ?? (avatars[0] ?? '😀'));
    setRole(props.initialProfile?.role ?? '');
    setEmailNotifications(props.initialProfile?.emailNotifications ?? true);
    setTheme(props.initialProfile?.theme === 'dark' ? 'dark' : 'light');
  }, [props.initialProfile, avatars]);

  const emailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()), [email]);
  const stepOneValid = name.trim().length > 0 && emailValid && avatar.trim().length > 0;
  const stepTwoValid = role.trim().length > 0 && (theme === 'light' || theme === 'dark');
  const canGoNext = (step === 1 && stepOneValid) || (step === 2 && stepTwoValid);
  const progressValue = useMemo(() => (step / 3) * 100, [step]);

  const handleNext = useCallback(() => {
    if (!canGoNext) return;
    setStep((prev) => (prev < 3 ? prev + 1 : prev));
  }, [canGoNext]);

  const handleBack = useCallback(() => {
    setStep((prev) => (prev > 1 ? prev - 1 : prev));
  }, []);

  const handleComplete = useCallback(() => {
    if (!stepOneValid || !stepTwoValid) return;
    complete({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
  }, [stepOneValid, stepTwoValid, complete, name, email, avatar, role, emailNotifications, theme]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="md" radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center">
              <Heading level={3}>Onboarding Wizard</Heading>
              <Badge variant="primary">Step {step} of 3</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" />
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              {step === 1 ? 'Profile Setup' : step === 2 ? 'Preferences' : 'Review & Confirm'}
            </Text>
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-6)" shadow="sm" radius="lg">
          <Box
            style={{
              animation: 'ggui-fadeIn 200ms ease-out',
              transition: 'all 200ms ease-in-out',
            }}
          >
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Profile Setup</Heading>
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  placeholder="Enter your full name"
                  required
                  error={name.trim().length === 0 ? 'Name is required' : undefined}
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  placeholder="you@example.com"
                  required
                  error={email.trim().length > 0 && !emailValid ? 'Please enter a valid email address' : undefined}
                />
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label">Choose an avatar</Text>
                  <Row gap="var(--ggui-spacing-3)" wrap>
                    {avatars.map((emoji, index) => (
                      <Card
                        key={`${emoji}-${index}`}
                        as={Clickable}
                        onClick={() => setAvatar(emoji)}
                        padding="var(--ggui-spacing-3)"
                        border
                        shadow="none"
                        radius="md"
                        style={{
                          borderColor: avatar === emoji ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)',
                          background: avatar === emoji ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)',
                        }}
                      >
                        <Text size="2xl" align="center">{emoji}</Text>
                      </Card>
                    ))}
                  </Row>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Preferences</Heading>
                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  placeholder="Select your role"
                  options={roles.map((item) => ({ value: item, label: item }))}
                  required
                  error={role.trim().length === 0 ? 'Role is required' : undefined}
                />
                <Toggle
                  label="Email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                />
                <Toggle
                  label={`Theme preference: ${theme === 'dark' ? 'Dark' : 'Light'}` }
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Review & Confirm</Heading>
                <Alert variant="info" title="Please review your information">
                  You can go back to edit any field before completing setup.
                </Alert>
                <Card padding="var(--ggui-spacing-4)" shadow="none" radius="md">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Row justify="between"><Text variant="label">Name</Text><Text>{name || '-'}</Text></Row>
                    <Row justify="between"><Text variant="label">Email</Text><Text>{email || '-'}</Text></Row>
                    <Row justify="between"><Text variant="label">Avatar</Text><Text>{avatar || '-'}</Text></Row>
                    <Row justify="between"><Text variant="label">Role</Text><Text>{role || '-'}</Text></Row>
                    <Row justify="between"><Text variant="label">Email Notifications</Text><Text>{emailNotifications ? 'On' : 'Off'}</Text></Row>
                    <Row justify="between"><Text variant="label">Theme</Text><Text>{theme}</Text></Row>
                  </Stack>
                </Card>
              </Stack>
            )}
          </Box>
        </Card>

        <Row justify="between" align="center">
          <Button variant="outline" onClick={handleBack} disabled={step === 1}>
            Back
          </Button>
          {step < 3 ? (
            <Button variant="primary" onClick={handleNext} disabled={!canGoNext}>
              Next
            </Button>
          ) : (
            <Row gap="var(--ggui-spacing-3)">
              <Button variant="outline" onClick={handleBack}>
                Go Back
              </Button>
              <Button variant="primary" onClick={handleComplete} disabled={!stepOneValid || !stepTwoValid}>
                Complete Setup
              </Button>
            </Row>
          )}
        </Row>
      </Stack>
    </Container>

  );
}
